using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change: HasData now throws for temporal values like DateTime.UtcNow.
        // Use a fixed constant instead.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; }

}

// --- Cosmos DB context demonstrating EF9 breaking changes ---
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ShopDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change #1: Cosmos provider now uses "$type" as the discriminator
        // property name by default instead of "Discriminator".
        // For existing documents that already use "Discriminator", explicitly configure it:
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");

        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasPartitionKey(p => p.Category);
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public string Category { get; set; } = default!;
}

// EF9 breaking change #2: Synchronous I/O on Cosmos DB is no longer supported.
// All queries/saves must use async methods.
class CosmosQueryService
{
    // WRONG (EF8): var products = db.Products.ToList();
    // CORRECT (EF9): use async
    async Task<List<Product>> GetProductsAsync(CosmosDbContext db)
    {
        return await db.Products.ToListAsync();
    }

    async Task SaveProductAsync(CosmosDbContext db, Product product)
    {
        db.Products.Add(product);
        await db.SaveChangesAsync();
    }
}

